mapper.select:
SELECT dr.device_id as deviceId, d.device_name as deviceName, COUNT(dr.record_id) as usageCount, SUM(dr.water_consumption) as totalWaterOutput, AVG(dr.water_consumption) as avgWaterPerUse, MAX(dr.drink_time) as lastUsageTime FROM drink_record dr LEFT JOIN device d ON dr.device_id = d.device_id WHERE 1=1
AND DATE(dr.drink_time) >= #{startDate}
AND DATE(dr.drink_time) <= #{endDate}
AND d.area_id = #{areaId}
GROUP BY dr.device_id, d.device_name ORDER BY totalWaterOutput DESC
LIMIT #{limit}

SELECT a.area_id as areaId, a.area_name as areaName, COUNT(dr.record_id) as usageCount, SUM(dr.water_consumption) as totalWaterOutput, COUNT(DISTINCT dr.device_id) as deviceCount FROM drink_record dr LEFT JOIN device d ON dr.device_id = d.device_id LEFT JOIN area a ON d.area_id = a.area_id WHERE 1=1
AND DATE(dr.drink_time) >= #{startDate}
AND DATE(dr.drink_time) <= #{endDate}
AND d.device_type = #{deviceType}
AND a.area_id IS NOT NULL GROUP BY a.area_id, a.area_name ORDER BY totalWaterOutput DESC
LIMIT #{limit}

choose.when:
SELECT
DATE_FORMAT(dr.drink_time, '%Y-%m-%d') as timeLabel,
COUNT(dr.record_id) as usageCount,
SUM(dr.water_consumption) as totalWaterOutput
FROM drink_record dr
WHERE 1=1

    AND DATE(dr.drink_time) >= #{startDate}


    AND DATE(dr.drink_time) <= #{endDate}


    AND dr.device_id = #{deviceId}


    AND dr.device_id IN (
    SELECT device_id FROM device WHERE area_id = #{areaId}
    )

GROUP BY DATE_FORMAT(dr.drink_time, '%Y-%m-%d')
ORDER BY timeLabel

SELECT
CONCAT(YEAR(dr.drink_time), '-W', WEEK(dr.drink_time, 1)) as timeLabel,
COUNT(dr.record_id) as usageCount,
SUM(dr.water_consumption) as totalWaterOutput
FROM drink_record dr
WHERE 1=1

    AND DATE(dr.drink_time) >= #{startDate}


    AND DATE(dr.drink_time) <= #{endDate}


    AND dr.device_id = #{deviceId}


    AND dr.device_id IN (
    SELECT device_id FROM device WHERE area_id = #{areaId}
    )

GROUP BY YEAR(dr.drink_time), WEEK(dr.drink_time, 1)
ORDER BY timeLabel

SELECT
DATE_FORMAT(dr.drink_time, '%Y-%m') as timeLabel,
COUNT(dr.record_id) as usageCount,
SUM(dr.water_consumption) as totalWaterOutput
FROM drink_record dr
WHERE 1=1

    AND DATE(dr.drink_time) >= #{startDate}


    AND DATE(dr.drink_time) <= #{endDate}


    AND dr.device_id = #{deviceId}


    AND dr.device_id IN (
    SELECT device_id FROM device WHERE area_id = #{areaId}
    )

GROUP BY DATE_FORMAT(dr.drink_time, '%Y-%m')
ORDER BY timeLabel

mapper.select:
SELECT a.device_id as deviceId, d.device_name as deviceName, COUNT(a.alert_id) as totalAlarms, SUM(CASE WHEN a.status = 'pending' THEN 1 ELSE 0 END) as pendingAlarms, SUM(CASE WHEN a.status = 'resolved' THEN 1 ELSE 0 END) as resolvedAlarms, MAX(a.timestamp) as lastAlarmTime FROM alert a LEFT JOIN device d ON a.device_id = d.device_id WHERE 1=1
AND DATE(a.timestamp) >= #{startDate}
AND DATE(a.timestamp) <= #{endDate}
AND d.area_id = #{areaId}
AND a.alert_level = #{alarmLevel}
GROUP BY a.device_id, d.device_name ORDER BY totalAlarms DESC
LIMIT #{limit}

SELECT a.area_id as areaId, ar.area_name as areaName, COUNT(al.alert_id) as totalAlarms, SUM(CASE WHEN al.status = 'pending' THEN 1 ELSE 0 END) as pendingAlarms, COUNT(DISTINCT al.device_id) as affectedDeviceCount FROM alert al LEFT JOIN device d ON al.device_id = d.device_id LEFT JOIN area ar ON d.area_id = ar.area_id WHERE 1=1
AND DATE(al.timestamp) >= #{startDate}
AND DATE(al.timestamp) <= #{endDate}
AND d.device_type = #{deviceType}
AND ar.area_id IS NOT NULL GROUP BY a.area_id, ar.area_name ORDER BY totalAlarms DESC
LIMIT #{limit}

SELECT COUNT(*) as totalDevices, SUM(CASE WHEN status = 'online' THEN 1 ELSE 0 END) as onlineDevices, SUM(CASE WHEN status = 'offline' THEN 1 ELSE 0 END) as offlineDevices, SUM(CASE WHEN status = 'fault' THEN 1 ELSE 0 END) as faultDevices, SUM(CASE WHEN status = 'maintenance' THEN 1 ELSE 0 END) as maintenanceDevices, ROUND(SUM(CASE WHEN status = 'online' THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 2) as onlineRate FROM device WHERE 1=1
AND area_id = #{areaId}
AND device_type = #{deviceType}

SELECT COUNT(*) as totalAlarms, SUM(CASE WHEN status = 'pending' THEN 1 ELSE 0 END) as pendingAlarms, SUM(CASE WHEN status = 'processing' THEN 1 ELSE 0 END) as processingAlarms, SUM(CASE WHEN status = 'resolved' THEN 1 ELSE 0 END) as resolvedAlarms, AVG(TIMESTAMPDIFF(HOUR, timestamp, resolved_time)) as avgResponseHours, MAX(TIMESTAMPDIFF(HOUR, timestamp, resolved_time)) as maxResponseHours FROM alert WHERE 1=1
AND DATE(timestamp) >= #{startDate}
AND DATE(timestamp) <= #{endDate}
AND area_id = #{areaId}
